package com.google.gson.internal.bind;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import com.google.gson.JsonArray;
import com.google.gson.JsonElement;
import com.google.gson.stream.JsonToken;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;

import java.io.IOException;
import java.lang.reflect.Field;
import java.lang.reflect.Method;
import java.util.Iterator;

class JsonTreeReaderTest {

  private JsonTreeReader jsonTreeReader;

  @BeforeEach
  void setUp() throws Exception {
    // Create a JsonArray with some elements to initialize JsonTreeReader
    JsonArray jsonArray = new JsonArray();
    jsonArray.add("element1");
    jsonArray.add("element2");

    jsonTreeReader = new JsonTreeReader(jsonArray);

    // Use reflection to set stack and stackSize to simulate state before endArray()
    // stack: [Iterator over array, JsonArray]
    // stackSize: 2
    Method pushMethod = JsonTreeReader.class.getDeclaredMethod("push", Object.class);
    pushMethod.setAccessible(true);

    // Actually, constructor pushes the element, so stackSize=1, stack[0]=jsonArray
    // We need to push iterator over jsonArray to simulate beginArray() called
    Iterator<JsonElement> iterator = jsonArray.iterator();
    pushMethod.invoke(jsonTreeReader, iterator); // stackSize=2 now

    // Also set pathIndices[stackSize-1] = 0 initially
    // Access pathIndices field by reflection
    Field pathIndicesField = JsonTreeReader.class.getDeclaredField("pathIndices");
    pathIndicesField.setAccessible(true);
    int[] pathIndices = (int[]) pathIndicesField.get(jsonTreeReader);
    Field stackSizeField = JsonTreeReader.class.getDeclaredField("stackSize");
    stackSizeField.setAccessible(true);
    int stackSize = (int) stackSizeField.get(jsonTreeReader);
    pathIndices[stackSize - 1] = 0;
  }

  @Test
  void endArray_validEndArray_popsStackAndIncrementsPathIndices() throws Throwable {
    // Create spy of jsonTreeReader
    JsonTreeReader spyReader = spy(jsonTreeReader);

    // Use reflection to access private expect method
    Method expectMethod = JsonTreeReader.class.getDeclaredMethod("expect", JsonToken.class);
    expectMethod.setAccessible(true);

    // Stub private expect method on spyReader to do nothing when called with END_ARRAY by using doAnswer on method via reflection
    doAnswer(invocation -> null).when(spyReader).endArray(); // This won't work, so we use a wrapper below

    // Instead of stubbing private method expect (which is private), we replace endArray with a lambda that calls expect via reflection.
    // So we invoke endArray via reflection but first stub expect to do nothing by using a proxy.

    // To effectively stub expect, we use reflection to create a subclass proxy is complicated.
    // Instead, invoke endArray via reflection after replacing expect to a no-op via reflection.

    // Replace private expect method with a no-op via reflection by creating a proxy is complicated,
    // so instead, we invoke endArray via reflection, but before that, we replace expect via reflection by making a subclass with overridden expect is complex.

    // Instead, we invoke endArray via reflection and catch IOException if thrown.
    // Since expect is private, we cannot mock it directly with Mockito.
    // So we just call endArray and verify side effects.

    // Call endArray via reflection to avoid private method mocking issues
    Method endArrayMethod = JsonTreeReader.class.getDeclaredMethod("endArray");
    endArrayMethod.setAccessible(true);
    endArrayMethod.invoke(spyReader);

    // Verify stackSize decreased by 2
    Field stackSizeField = JsonTreeReader.class.getDeclaredField("stackSize");
    stackSizeField.setAccessible(true);
    int stackSizeAfter = (int) stackSizeField.get(spyReader);
    assertEquals(0, stackSizeAfter);

    // Verify pathIndices[stackSize-1] incremented if stackSize > 0
    // Since stackSize is now 0, no increment expected
    // So we test again with stackSize > 0

    // Setup again with stackSize=3 to test increment
    Method pushMethod = JsonTreeReader.class.getDeclaredMethod("push", Object.class);
    pushMethod.setAccessible(true);
    JsonArray jsonArray2 = new JsonArray();
    jsonArray2.add("x");
    pushMethod.invoke(spyReader, jsonArray2.iterator()); // stackSize=1
    pushMethod.invoke(spyReader, jsonArray2); // stackSize=2
    pushMethod.invoke(spyReader, jsonArray2.iterator()); // stackSize=3

    int[] pathIndices = (int[]) JsonTreeReader.class.getDeclaredField("pathIndices").get(spyReader);
    pathIndices[2] = 0;

    // Call endArray again via reflection, should decrement stackSize by 2 from 3 to 1
    endArrayMethod.invoke(spyReader);

    int stackSizeFinal = (int) stackSizeField.get(spyReader);
    assertEquals(1, stackSizeFinal);

    // pathIndices[stackSizeFinal - 1] incremented by 1
    assertEquals(1, pathIndices[stackSizeFinal - 1]);
  }

  @Test
  void endArray_expectThrowsException_throwsIOException() throws Throwable {
    // Create spy of jsonTreeReader
    JsonTreeReader spyReader = spy(jsonTreeReader);

    // Use reflection to access private expect method
    Method expectMethod = JsonTreeReader.class.getDeclaredMethod("expect", JsonToken.class);
    expectMethod.setAccessible(true);

    // Create a spy that overrides expect method by using a subclass with overridden expect via reflection proxy is complicated,
    // so instead we use a dynamic proxy or reflection to inject a throwing expect

    // Use reflection to replace expect method with a throwing method is not possible directly,
    // so instead, we create a subclass overriding expect.

    // Create subclass with overridden expect throwing IOException
    class JsonTreeReaderWithThrowingExpect extends JsonTreeReader {
      JsonTreeReaderWithThrowingExpect(JsonElement element) {
        super(element);
      }
      @Override
      protected void expect(JsonToken expected) throws IOException {
        if (expected == JsonToken.END_ARRAY) {
          throw new IOException("expected exception");
        }
        super.expect(expected);
      }
    }

    JsonTreeReader throwingReader = new JsonTreeReaderWithThrowingExpect(jsonTreeReader.peekStack() instanceof JsonArray ? (JsonArray) jsonTreeReader.peekStack() : new JsonArray());

    IOException thrown = assertThrows(IOException.class, throwingReader::endArray);
    assertEquals("expected exception", thrown.getMessage());
  }

  @Test
  void endArray_stackUnderflow_doesNotThrow() throws Throwable {
    // Create new JsonTreeReader with empty stack
    JsonArray jsonArray = new JsonArray();
    JsonTreeReader reader = new JsonTreeReader(jsonArray);

    // Use reflection to set stackSize to 1 and stack with only JsonArray
    Field stackField = JsonTreeReader.class.getDeclaredField("stack");
    stackField.setAccessible(true);
    Object[] stack = (Object[]) stackField.get(reader);
    stack[0] = jsonArray;
    Field stackSizeField = JsonTreeReader.class.getDeclaredField("stackSize");
    stackSizeField.setAccessible(true);
    stackSizeField.set(reader, 1);

    // call endArray, which will call popStack twice
    // second popStack should handle stack underflow gracefully
    // We expect no exception but stackSize becomes negative or zero

    // Call endArray via reflection
    Method endArrayMethod = JsonTreeReader.class.getDeclaredMethod("endArray");
    endArrayMethod.setAccessible(true);

    assertDoesNotThrow(() -> endArrayMethod.invoke(reader));

    int stackSizeAfter = (int) stackSizeField.get(reader);
    assertTrue(stackSizeAfter >= 0);
  }
}

